create table dirkspzm32.dw_lvs_bestand (
    sid                 varchar2(2 char) not null enable,
    firma_nr            number(2, 0) not null enable,
    dw_stat_id          number(*, 0) not null enable,
    stat_name           varchar2(200 char) not null enable,
    erfasst_am          date not null enable,
    lgr_ort             number(5, 0),
    artikel_id          number(*, 0),
    leitzahl            number(*, 5),
    fa_ag               number(*, 5),
    charge_id           number(*, 0),
    mhd                 date,
    labor_status        varchar2(1 char),
    lte_name            varchar2(22 char),
    lte_status          varchar2(2 char),
    sum_menge           number(*, 3),
    anz_lam             number(*, 0),
    anz_lte             number(10, 4),
    basis_lte_name      varchar2(22 char),
    wert_datum          date,
    wert_datum_ende     date,
    menge_basis         varchar2(3 char) default 'LKE',
    mengeneinheit_basis varchar2(10 char) default 'STK'
);

alter table dirkspzm32.dw_lvs_bestand
    add constraint pk_dw_lvs_bestand primary key ( dw_stat_id )
        using index enable;


